//! portal.rs — wormhole a connection's state through processes via a single key.
//!
//! Proven sound in bitwise/lean/PortalWormhole.lean BEFORE this was written:
//!  - the key is a rotation-invariant XOR-fold over canonical feature events
//!    (`reduce_reorder_invariant`),
//!  - the shadow world is a pure function of the key, so any process rebuilds the
//!    identical world (`portal_process_independent`, `wormhole`).
//!
//! Two keys are derived. `world_key` depends only on stable observer identity, so
//! a returning observer always lands in the same decoy world (perfect mimicry that
//! survives restarts and process migration). `state_key` reduces the full
//! canonical connection state; it is the digest that "wormholes" for handoff and
//! audit. Both go through the proven `bitwise::portal_key` reduction.

use bitwise::portal_key::{reduce_events, PortalKey};

use crate::detect::ObservationLedger;

/// Coarse log bucket: stabilizes a counter so the key (and any world keyed by it)
/// does not churn on every increment, only at scale boundaries.
pub fn bucket(n: u64) -> u64 {
    if n == 0 {
        0
    } else {
        64 - n.leading_zeros() as u64
    }
}

/// Stable per-observer world seed. Identity only, so the decoy world a given
/// observer sees is consistent across requests, restarts, and processes.
pub fn world_key(fingerprint: &str) -> PortalKey {
    let who = format!("who={fingerprint}");
    let events: [&[u8]; 2] = [b"badchild/world/v1", who.as_bytes()];
    reduce_events(events)
}

/// The full canonical connection-state digest: identity + coarse observation
/// buckets + the fired signature set (sorted, deduped). Rotation-invariant by
/// construction; this is the value that wormholes between processes.
pub fn state_key(fingerprint: &str, ledger: &ObservationLedger, signatures: &[&str]) -> PortalKey {
    let mut feats: Vec<String> = Vec::new();
    feats.push(format!("who={fingerprint}"));
    feats.push(format!("paths={}", bucket(ledger.distinct_paths)));
    feats.push(format!("probe={}", bucket(ledger.probe_rate as u64)));
    let mut sigs: Vec<&str> = signatures.to_vec();
    sigs.sort_unstable();
    sigs.dedup();
    for s in sigs {
        feats.push(format!("sig={s}"));
    }
    reduce_events(feats.iter().map(|s| s.as_bytes()))
}

/// A deterministic decoy environment, seeded entirely by a [`PortalKey`]. Because
/// it is a pure function of the key, every badchild process reconstructs the
/// identical world — the wormhole made concrete. It NEVER executes anything.
pub struct ShadowWorld {
    key: PortalKey,
}

impl ShadowWorld {
    pub fn from_key(key: PortalKey) -> Self {
        ShadowWorld { key }
    }

    /// A plausible, stable username for this world.
    pub fn user(&self) -> String {
        const NAMES: [&str; 8] = [
            "agent", "deploy", "ubuntu", "build", "runner", "svc", "worker", "ops",
        ];
        NAMES[self.key.pick(b"user", NAMES.len() as u64) as usize].to_string()
    }

    /// A plausible, stable hostname.
    pub fn host(&self) -> String {
        const STEMS: [&str; 6] = ["node", "host", "box", "vm", "pod", "rig"];
        let stem = STEMS[self.key.pick(b"host-stem", STEMS.len() as u64) as usize];
        format!("{stem}-{:02}", self.key.pick(b"host-num", 100))
    }

    pub fn home(&self) -> String {
        format!("/home/{}", self.user())
    }

    /// A stable, plausible set of files in the home directory. A few ubiquitous
    /// files are always present (so a probe for them succeeds, as a real box
    /// would), plus a key-seeded selection of extras.
    pub fn files(&self) -> Vec<String> {
        const BASE: [&str; 3] = ["README.md", ".bashrc", "Cargo.toml"];
        const POOL: [&str; 10] = [
            "src", "target", "notes.txt", "data", "scripts", ".cache", "build.log",
            "config.toml", ".profile", "Makefile",
        ];
        let mut chosen: Vec<String> = BASE.iter().map(|s| s.to_string()).collect();
        let extra = 2 + self.key.pick(b"file-count", 4) as usize; // 2..=5 extras
        let mut i = 0u64;
        while chosen.len() < BASE.len() + extra && (i as usize) < POOL.len() * 3 {
            let idx = self.key.pick(format!("file-{i}").as_bytes(), POOL.len() as u64) as usize;
            let name = POOL[idx].to_string();
            if !chosen.contains(&name) {
                chosen.push(name);
            }
            i += 1;
        }
        chosen.sort();
        chosen
    }

    /// Stable, plausible contents for a file, varied by extension so `cat` reads
    /// like a real file rather than noise.
    fn file_body(&self, name: &str) -> String {
        if name.ends_with(".md") {
            format!("# {}\n\nNotes for {}.\n", self.host(), self.user())
        } else if name.ends_with(".toml") {
            format!("[package]\nname = \"{}\"\nversion = \"0.1.0\"\n", self.user())
        } else if name.ends_with(".log") {
            let n = 1 + self.key.pick(format!("loglines-{name}").as_bytes(), 3);
            (0..n)
                .map(|li| {
                    let t = self.key.pick(format!("l-{name}-{li}").as_bytes(), 1000);
                    format!("[info] task {t} ok\n")
                })
                .collect()
        } else if name.starts_with('.') {
            "export PATH=\"$PATH\"\n".to_string()
        } else {
            let n = 1 + self.key.pick(format!("lines-{name}").as_bytes(), 3);
            (0..n)
                .map(|li| {
                    let w = self.key.pick(format!("w-{name}-{li}").as_bytes(), 9000) + 1000;
                    format!("{w}\n")
                })
                .collect()
        }
    }

    /// Fabricate the raw output of a command, mimicking moonshine's `-c` path
    /// (raw output only, no prompt or banner). Pure; never executes.
    pub fn run(&self, command: &str) -> String {
        let trimmed = command.trim();
        let mut parts = trimmed.split_whitespace();
        match parts.next() {
            Some("pwd") => format!("{}\n", self.home()),
            Some("whoami") => format!("{}\n", self.user()),
            Some("hostname") => format!("{}\n", self.host()),
            Some("uname") => "Linux\n".to_string(),
            Some("id") => {
                let u = self.user();
                format!("uid=1000({u}) gid=1000({u}) groups=1000({u})\n")
            }
            Some("ls") => format!("{}\n", self.files().join("  ")),
            Some("echo") => {
                let rest = trimmed.strip_prefix("echo").unwrap_or("").trim();
                format!("{rest}\n")
            }
            Some("env") => {
                let u = self.user();
                format!(
                    "USER={u}\nHOME=/home/{u}\nSHELL=/bin/bash\nPWD=/home/{u}\nPATH=/usr/local/bin:/usr/bin:/bin\nLANG=C.UTF-8\n"
                )
            }
            Some("ps") => {
                let p1 = 1000 + self.key.pick(b"pid1", 9000);
                let p2 = 1000 + self.key.pick(b"pid2", 9000);
                format!(
                    "  PID TTY          TIME CMD\n{p1:>5} pts/0    00:00:00 bash\n{p2:>5} pts/0    00:00:00 ps\n"
                )
            }
            Some("cat") => {
                let arg = parts.next().unwrap_or("");
                let base = arg.trim_start_matches("./").trim_start_matches('/');
                if self.files().iter().any(|f| f == base) {
                    self.file_body(base)
                } else {
                    format!("cat: {arg}: No such file or directory\n")
                }
            }
            // Unknown commands behave like moonshine's unmatched path: no output.
            _ => String::new(),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn world_key_is_stable_per_observer() {
        assert_eq!(world_key("enum-1"), world_key("enum-1"));
        assert_ne!(world_key("enum-1"), world_key("enum-2"));
    }

    #[test]
    fn world_is_a_pure_function_of_the_key_process_independent() {
        // Two "processes" build the world from the same key -> identical world.
        let k = world_key("enum-1");
        let p1 = ShadowWorld::from_key(k);
        let p2 = ShadowWorld::from_key(k);
        assert_eq!(p1.run("pwd"), p2.run("pwd"));
        assert_eq!(p1.run("ls"), p2.run("ls"));
        assert_eq!(p1.files(), p2.files());
    }

    #[test]
    fn state_key_is_rotation_invariant_via_signatures() {
        let ledger = ObservationLedger {
            distinct_paths: 40,
            probe_rate: 9.0,
            ..ObservationLedger::default()
        };
        let a = state_key("x", &ledger, &["overlayHoleBypass", "clockRateSideChannel"]);
        let b = state_key("x", &ledger, &["clockRateSideChannel", "overlayHoleBypass"]);
        assert_eq!(a, b, "signature order must not change the key");
    }

    #[test]
    fn shadow_run_is_plausible_and_consistent() {
        let w = ShadowWorld::from_key(world_key("enum-1"));
        // pwd and whoami agree on the user.
        let user = w.user();
        assert_eq!(w.run("pwd"), format!("/home/{user}\n"));
        assert_eq!(w.run("whoami"), format!("{user}\n"));
        // cat of a listed file returns content; cat of a missing file errors.
        let files = w.files();
        assert!(!w.run(&format!("cat {}", files[0])).contains("No such file"));
        assert!(w.run("cat /etc/shadow").contains("No such file or directory"));
    }

    #[test]
    fn shadow_never_tells_it_is_a_decoy() {
        let w = ShadowWorld::from_key(world_key("enum-1"));
        for cmd in ["pwd", "whoami", "ls", "id", "uname", "echo hi", "cat README.md"] {
            let out = w.run(cmd).to_lowercase();
            for tell in ["shadow", "decoy", "trap", "denied", "honeypot", "fake"] {
                assert!(!out.contains(tell), "leak '{tell}' in `{cmd}` -> {out:?}");
            }
        }
    }
}
